import{_ as a,o as e,c as r,a6 as l}from"./chunks/framework.Bf5o6qNq.js";const u=JSON.parse('{"title":"《禁忌的Show》劇情轉折點設計文件：第 3 - 4 天","description":"","frontmatter":{},"headers":[],"relativePath":"story/劇情腳本_第三四天.md","filePath":"story/劇情腳本_第三四天.md"}'),o={name:"story/劇情腳本_第三四天.md"};function n(i,t,s,h,d,g){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="《禁忌的show》劇情轉折點設計文件-第-3-4-天" tabindex="-1">《禁忌的Show》劇情轉折點設計文件：第 3 - 4 天 <a class="header-anchor" href="#《禁忌的show》劇情轉折點設計文件-第-3-4-天" aria-label="Permalink to &quot;《禁忌的Show》劇情轉折點設計文件：第 3 - 4 天&quot;">​</a></h1><p>本文件詳細規範遊戲中第 3 天至第 4 天的關鍵劇情轉折點，包含匿名簡訊系統、AI 敵意機制及小遊戲聯動。</p><hr><h2 id="一、-第-3-天晚上-匿名簡訊系統-the-anonymous-sms" tabindex="-1">一、 第 3 天晚上：匿名簡訊系統 (The Anonymous SMS) <a class="header-anchor" href="#一、-第-3-天晚上-匿名簡訊系統-the-anonymous-sms" aria-label="Permalink to &quot;一、 第 3 天晚上：匿名簡訊系統 (The Anonymous SMS)&quot;">​</a></h2><h3 id="_1-1-觸發條件" tabindex="-1">1.1 觸發條件 <a class="header-anchor" href="#_1-1-觸發條件" aria-label="Permalink to &quot;1.1 觸發條件&quot;">​</a></h3><ul><li><strong>時間點</strong>：第 3 天晚上 (Evening) 活動結束後，點擊「結算」按鈕前。</li><li><strong>參與角色</strong>：僅限初期三位女主角（搖滾少女、清純少女、運動少女）。</li></ul><h3 id="_1-2-簡訊反饋劇情" tabindex="-1">1.2 簡訊反饋劇情 <a class="header-anchor" href="#_1-2-簡訊反饋劇情" aria-label="Permalink to &quot;1.2 簡訊反饋劇情&quot;">​</a></h3><p>當玩家選擇對象後，畫面將切換至該女主角房間的剪影，顯示其心情獨白：</p><table tabindex="0"><thead><tr><th style="text-align:left;">女主角</th><th style="text-align:left;">心情獨白內容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>搖滾少女</strong></td><td style="text-align:left;">「（斜眼看手機）這傢伙...眼光還不算太差嘛。既然你這麼主動，那我就稍微期待一下你之後的表現好了。」</td></tr><tr><td style="text-align:left;"><strong>清純少女</strong></td><td style="text-align:left;">「（臉紅握著手機）原來...他一直在關注我嗎？好開心...這晚我可能會興奮到睡不著呢。」</td></tr><tr><td style="text-align:left;"><strong>運動少女</strong></td><td style="text-align:left;">「（爽朗大笑）嘿，看來這場比賽越來越有趣了！有眼光！明天的小遊戲，可別讓我失望啊！」</td></tr></tbody></table><hr><h2 id="二、-第-4-天早上-ai-敵意衝突-the-rivalry" tabindex="-1">二、 第 4 天早上：AI 敵意衝突 (The Rivalry) <a class="header-anchor" href="#二、-第-4-天早上-ai-敵意衝突-the-rivalry" aria-label="Permalink to &quot;二、 第 4 天早上：AI 敵意衝突 (The Rivalry)&quot;">​</a></h2><h3 id="_2-1-敵意產生規則" tabindex="-1">2.1 敵意產生規則 <a class="header-anchor" href="#_2-1-敵意產生規則" aria-label="Permalink to &quot;2.1 敵意產生規則&quot;">​</a></h3><p>系統根據玩家在第 3 天的選擇，自動判定產生敵意的 AI 對手：</p><ul><li>選擇 <strong>搖滾少女</strong> → <strong>高冷男</strong> 產生敵意。</li><li>選擇 <strong>清純少女</strong> → <strong>暖男</strong> 產生敵意。</li><li>選擇 <strong>運動少女</strong> → <strong>體育男</strong> 產生敵意。</li></ul><h3 id="_2-2-通用衝突對話-第-4-天早上入口觸發" tabindex="-1">2.2 通用衝突對話 (第 4 天早上入口觸發) <a class="header-anchor" href="#_2-2-通用衝突對話-第-4-天早上入口觸發" aria-label="Permalink to &quot;2.2 通用衝突對話 (第 4 天早上入口觸發)&quot;">​</a></h3><h4 id="與高冷男-敵意-精準壓制" tabindex="-1"><strong>與高冷男 (敵意：精準壓制)</strong> <a class="header-anchor" href="#與高冷男-敵意-精準壓制" aria-label="Permalink to &quot;**與高冷男 (敵意：精準壓制)**&quot;">​</a></h4><ul><li><strong>對話</strong>：「昨晚的簡訊...我看到了。別以為靠衝動就能贏得她的青睞。等下的遊戲，我會讓你明白什麼叫真正的層次感。」</li></ul><h4 id="與體育男-敵意-力量挑釁" tabindex="-1"><strong>與體育男 (敵意：力量挑釁)</strong> <a class="header-anchor" href="#與體育男-敵意-力量挑釁" aria-label="Permalink to &quot;**與體育男 (敵意：力量挑釁)**&quot;">​</a></h4><ul><li><strong>對話</strong>：「嘿！VIP 大哥，昨晚挺敢發的嘛！但在這園區，實力才是一切。等下不管玩什麼，我都會把你甩在後頭！」</li></ul><h4 id="與暖男-敵意-笑裡藏刀" tabindex="-1"><strong>與暖男 (敵意：笑裡藏刀)</strong> <a class="header-anchor" href="#與暖男-敵意-笑裡藏刀" aria-label="Permalink to &quot;**與暖男 (敵意：笑裡藏刀)**&quot;">​</a></h4><ul><li><strong>對話</strong>：「早安。昨晚你發簡訊給她了吧？其實，我也發了。因為我覺得，她值得更細緻的呵護。等下的比賽，我不會再退讓了。」</li></ul><hr><h2 id="三、-小遊戲聯動機制-mini-game-synergy" tabindex="-1">三、 小遊戲聯動機制 (Mini-Game Synergy) <a class="header-anchor" href="#三、-小遊戲聯動機制-mini-game-synergy" aria-label="Permalink to &quot;三、 小遊戲聯動機制 (Mini-Game Synergy)&quot;">​</a></h2><h3 id="_3-1-敵對-ai-數值加成-rival-buff" tabindex="-1">3.1 敵對 AI 數值加成 (Rival Buff) <a class="header-anchor" href="#_3-1-敵對-ai-數值加成-rival-buff" aria-label="Permalink to &quot;3.1 敵對 AI 數值加成 (Rival Buff)&quot;">​</a></h3><p>無論抽中哪一個隨機小遊戲，產生敵意的 AI 都會獲得強化：</p><table tabindex="0"><thead><tr><th style="text-align:left;">AI 對手</th><th style="text-align:left;">強化風格</th><th style="text-align:left;">具體影響</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>高冷男</strong></td><td style="text-align:left;"><strong>精準壓制</strong></td><td style="text-align:left;">減少判定誤差（舞蹈 Perfect 率提升、烤肉精準度提升、跑酷完美跳躍率提升）。</td></tr><tr><td style="text-align:left;"><strong>體育男</strong></td><td style="text-align:left;"><strong>爆發衝刺</strong></td><td style="text-align:left;">提升基礎數值（跑酷速度提升、舞蹈 Combo 分數加成、烤肉速度提升）。</td></tr><tr><td style="text-align:left;"><strong>暖男</strong></td><td style="text-align:left;"><strong>穩定發揮</strong></td><td style="text-align:left;">提高成功率下限（大幅減少 Miss 判定，給予玩家穩定的排名壓力）。</td></tr></tbody></table><h3 id="_3-2-女主角觀戰台詞" tabindex="-1">3.2 女主角觀戰台詞 <a class="header-anchor" href="#_3-2-女主角觀戰台詞" aria-label="Permalink to &quot;3.2 女主角觀戰台詞&quot;">​</a></h3><p>在小遊戲進行中或結算畫面，該女主角會發表專屬評論：</p><ul><li><strong>搖滾少女</strong>：「喂，那個 VIP，別讓我看扁了啊！拿出你的氣勢來！」</li><li><strong>清純少女</strong>：「雖然競爭很激烈...但我會一直看著努力的那個人...加油！」</li><li><strong>運動少女</strong>：「就是這樣！這才叫比賽嘛！輸掉的人可沒資格找我約會喔！」</li></ul><hr><h2 id="四、-勝負影響機制-affection-impact" tabindex="-1">四、 勝負影響機制 (Affection Impact) <a class="header-anchor" href="#四、-勝負影響機制-affection-impact" aria-label="Permalink to &quot;四、 勝負影響機制 (Affection Impact)&quot;">​</a></h2><h3 id="_4-1-玩家獲勝-擊敗敵對-ai" tabindex="-1">4.1 玩家獲勝 (擊敗敵對 AI) <a class="header-anchor" href="#_4-1-玩家獲勝-擊敗敵對-ai" aria-label="Permalink to &quot;4.1 玩家獲勝 (擊敗敵對 AI)&quot;">​</a></h3><ul><li><strong>好感度</strong>：該女主角對玩家 <strong>+20</strong>，對敵對 AI <strong>-5</strong>。</li><li><strong>演出</strong>：女主角賽後主動讚美玩家。</li></ul><h3 id="_4-2-玩家失敗-輸給敵對-ai" tabindex="-1">4.2 玩家失敗 (輸給敵對 AI) <a class="header-anchor" href="#_4-2-玩家失敗-輸給敵對-ai" aria-label="Permalink to &quot;4.2 玩家失敗 (輸給敵對 AI)&quot;">​</a></h3><ul><li><strong>好感度</strong>：該女主角對敵對 AI <strong>+20</strong>，對玩家 <strong>-15</strong>。</li><li><strong>演出</strong>：女主角對贏家表示讚賞，對玩家露出失望或遺憾的眼神。</li></ul><hr><h2 id="五、-技術實作備註" tabindex="-1">五、 技術實作備註 <a class="header-anchor" href="#五、-技術實作備註" aria-label="Permalink to &quot;五、 技術實作備註&quot;">​</a></h2><ul><li><strong>存檔 Key</strong>：<code>forbiddenShow_rivals</code> (儲存當前敵對 AI 名稱)。</li><li><strong>URL 參數</strong>：<code>rivalAI=cold|warm|sport</code> (傳遞給小遊戲頁面)。</li><li><strong>邏輯位置</strong>：主要邏輯位於 <code>index.html</code> (簡訊) 與 <code>morning-games.html</code> (衝突對話)。</li></ul>',38)])])}const f=a(o,[["render",n]]);export{u as __pageData,f as default};
